DROP TABLE IF EXISTS `data_kartu_keluarga`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `data_kartu_keluarga` (
  `id` int NOT NULL AUTO_INCREMENT,
  `no_kk` varchar(16) NOT NULL,
  `nik` varchar(16) NOT NULL,
  `nama_kepala_keluarga` varchar(16) NOT NULL,
  `alamat` text NOT NULL,
  `rt` varchar(3) NOT NULL,
  `rw` varchar(3) NOT NULL,
  `kelurahan` varchar(16) NOT NULL,
  `kecamatan` varchar(16) NOT NULL,
  `kabupaten` varchar(16) NOT NULL,
  `kodepos` varchar(6) NOT NULL,
  `status_warga` varchar(32) NOT NULL,
  `asal_kota` varchar(16) NOT NULL,
  `created_at` datetime NOT NULL DEFAULT (now()),
  PRIMARY KEY (`id`),
  UNIQUE KEY `ix_data_kartu_keluarga_no_kk` (`no_kk`),
  KEY `ix_data_kartu_keluarga_id` (`id`),
  KEY `ix_data_kartu_keluarga_nik` (`nik`)
) ENGINE=InnoDB AUTO_INCREMENT=22 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

