INSERT INTO `settings` VALUES ('layout_global','{\"footer\": {\"description\": \"Platform digital untuk membantu pengurus RT dan warga mengelola administrasi, komunikasi, dan layanan lingkungan secara lebih cepat, transparan, dan efisien.\"}, \"contact\": {\"email\": \"support@smartrt.id\", \"phone\": \"+62 812 3456 7890\", \"address\": \"Jakarta, Indonesia\"}}',NULL,'2026-03-04 12:46:56'),('layout_navigation','{\"brand\": {\"name\": \"Smart RT\", \"tagline\": \"Menghubungkan Warga, Mempermudah Layanan, dan Mewujudkan RT Digital.\"}, \"primary\": [{\"label\": \"Beranda\", \"href\": \"/\"}, {\"label\": \"Blog\", \"href\": \"/blogs\"}, {\"label\": \"Tentang Kami\", \"href\": \"/about\"}], \"secondary\": [{\"label\": \"Beranda\", \"href\": \"/\", \"icon\": \"Home\"}, {\"label\": \"Blog\", \"href\": \"/blogs\", \"icon\": \"Newspaper\"}, {\"label\": \"Tentang\", \"href\": \"/about\", \"icon\": \"Info\"}]}',NULL,'2026-03-04 12:46:56'),('page_about','{\"vision\": \"Menjadi platform digital komunitas yang membantu menciptakan lingkungan RT yang modern, transparan, terhubung, dan penuh semangat kebersamaan.\", \"mission\": \"- Menghadirkan sistem pengelolaan data warga dan kartu keluarga yang terorganisir dan mudah diakses.\\n- Menyediakan sistem pengelolaan keuangan dan iuran RT yang transparan dan akuntabel.\\n- Mempermudah penyampaian informasi, kegiatan, dan komunikasi antar warga.\\n- Mendukung nilai kebersamaan dan gotong royong melalui platform digital komunitas.\\n- Menyediakan fitur edukasi dan spiritual seperti Al-Qur\'an, hadist, dan informasi waktu sholat bagi warga.\\n- Mengembangkan teknologi yang sederhana, mudah digunakan, dan bermanfaat bagi masyarakat di tingkat lingkungan.\", \"story\": \"Perkembangan teknologi digital telah membawa perubahan besar dalam berbagai aspek kehidupan, termasuk dalam pengelolaan komunitas masyarakat di tingkat lingkungan seperti Rukun Tetangga (RT). Namun pada kenyataannya, banyak aktivitas administrasi dan komunikasi di lingkungan RT masih dilakukan secara manual, seperti pencatatan data warga, pengelolaan iuran, penyampaian informasi kegiatan, hingga dokumentasi administrasi.\\n\\nProses manual ini seringkali menimbulkan berbagai kendala, seperti data yang sulit dicari, transparansi keuangan yang kurang optimal, informasi kegiatan yang tidak tersampaikan secara merata, serta keterbatasan akses bagi warga yang tidak selalu berada di lingkungan RT.\\n\\nMelihat kebutuhan tersebut, lahirlah Smart RT, sebuah platform digital yang dirancang untuk membantu pengurus dan warga RT dalam mengelola administrasi, komunikasi, dan kegiatan lingkungan secara lebih modern, transparan, dan efisien. Smart RT tidak hanya menjadi alat manajemen data warga dan keuangan RT, tetapi juga menjadi pusat informasi dan edukasi bagi masyarakat melalui fitur seperti blog, Al-Qur\'an digital, hadist, serta informasi waktu sholat.\\n\\nDengan hadirnya Smart RT, diharapkan pengelolaan lingkungan RT dapat menjadi lebih tertata, transparan, serta mampu memperkuat nilai kebersamaan dan semangat gotong royong di tengah masyarakat.\"}',NULL,'2026-03-05 16:47:50'),('page_home','{\"hero\": {\"title\": \"Smart RT\", \"subtitle\": \"Smart RT menghadirkan solusi digital yang memudahkan pengelolaan data warga, pengajuan surat, pengumuman lingkungan, hingga pembayaran iuran semua dalam satu sistem terintegrasi yang dapat diakses kapan saja.\"}, \"features\": [{\"title\": \"Pengelolaan Data Warga Personal\", \"description\": \"Menyimpan dan mengelola data pribadi warga secara terstruktur, termasuk identitas, alamat, dan informasi penting lainnya untuk memudahkan administrasi RT.\", \"icon\": \"Users\"}, {\"title\": \"Pengelolaan Data Kartu Keluarga\", \"description\": \"Mengelola data Kartu Keluarga secara digital sehingga hubungan antar anggota keluarga dapat tercatat dengan rapi dan mudah diakses oleh pengurus RT.\", \"icon\": \"Users\"}, {\"title\": \"Pengelolaan Data Keuangan RT\", \"description\": \"Mencatat pemasukan dan pengeluaran kas RT secara transparan sehingga pengelolaan keuangan lingkungan menjadi lebih tertib dan akuntabel.\", \"icon\": \"BarChart3\"}, {\"title\": \"Pengelolaan Data Iuran RT\", \"description\": \"Mempermudah pencatatan iuran warga, status pembayaran, serta laporan iuran agar pengurus RT dapat mengelola keuangan dengan lebih efisien.\", \"icon\": \"BarChart3\"}, {\"title\": \"Pengelolaan Jadwal Kegiatan Warga\", \"description\": \"Mengatur dan mengelola jadwal kegiatan lingkungan seperti kerja bakti, rapat warga, dan acara komunitas agar seluruh warga dapat mengetahui agenda RT dengan jelas dan tepat waktu.\", \"icon\": \"Calendar\"}, {\"title\": \"Pengelolaan Blog Post\", \"description\": \"Menyediakan fitur publikasi artikel, berita, dan informasi lingkungan RT sehingga warga dapat selalu mendapatkan update terbaru dari komunitas.\", \"icon\": \"Globe\"}, {\"title\": \"Tema Powerful\", \"description\": \"Tampilan modern dan fleksibel dengan desain yang kuat, responsif, dan mudah disesuaikan agar website RT terlihat profesional dan nyaman digunakan.\", \"icon\": \"Zap\"}, {\"title\": \"Keamanan Data Terjamin\", \"description\": \"Melindungi data warga dengan sistem keamanan yang andal sehingga informasi penting tetap aman, terjaga privasinya, dan hanya dapat diakses oleh pihak yang berwenang.\", \"icon\": \"Shield\"}, {\"title\": \"Smart Quran\", \"description\": \"Menyediakan akses Al-Qur\\u2019an digital yang memudahkan warga untuk membaca, mencari ayat, dan memperdalam pemahaman Al-Qur\\u2019an langsung dari platform. (COMING SOON)\", \"icon\": \"Globe\"}, {\"title\": \"Smart Hadist\", \"description\": \"Menghadirkan kumpulan hadist yang dapat diakses dengan mudah untuk menambah wawasan keislaman serta menjadi pedoman dalam kehidupan sehari-hari. (COMING SOON)\", \"icon\": \"Globe\"}, {\"title\": \"Kumpulan Doa\", \"description\": \"Berisi berbagai doa harian yang dapat dibaca dan dipelajari oleh warga untuk mendukung kehidupan spiritual sehari-hari. (COMING SOON)\", \"icon\": \"Globe\"}, {\"title\": \"Waktu Shalat\", \"description\": \"Menampilkan jadwal waktu shalat yang akurat sesuai lokasi sehingga warga dapat mengetahui waktu ibadah dengan lebih mudah.\", \"icon\": \"Calendar\"}]}',NULL,'2026-03-04 13:02:07');
/*!40000 ALTER TABLE `settings` ENABLE KEYS */;
UNLOCK TABLES;

